class Solution:
    def removeDuplicateLetters(self, s):
        # Enumerate all subsequences with each letter exactly once,
        # maintaining relative order; return lex-smallest.
        chars = frozenset(s)
        n = len(s)
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def dp(idx, seen):
            # seen: frozenset of chars already chosen
            if seen == chars:
                return ''
            if idx == n:
                return None  # not all chars placed
            c = s[idx]
            best = None
            # Option 1: skip s[idx] (only if c still appears later)
            if c in set(s[idx+1:]) or c in seen:
                skip = dp(idx + 1, seen)
                if skip is not None:
                    best = skip
            # Option 2: take s[idx] if not yet seen
            if c not in seen:
                take = dp(idx + 1, seen | frozenset([c]))
                if take is not None:
                    candidate = c + take
                    if best is None or candidate < best:
                        best = candidate
            return best
        return dp(0, frozenset())

