class Solution:
    def removeDuplicateLetters(self, s):
        from collections import Counter
        count = Counter(s)
        used = set()
        stack = []
        for c in s:
            count[c] -= 1
            if c in used:
                continue
            while stack and stack[-1] > c and count[stack[-1]] > 0:
                used.discard(stack.pop())
            stack.append(c)
            used.add(c)
        return ''.join(stack)

