var removeDuplicateLetters = function(s) {
    const count = {};
    for (const c of s) count[c] = (count[c] || 0) + 1;
    const used = new Set();
    const stack = [];
    for (const c of s) {
        count[c]--;
        if (used.has(c)) continue;
        while (stack.length && stack[stack.length - 1] > c && count[stack[stack.length - 1]] > 0) {
            used.delete(stack.pop());
        }
        stack.push(c);
        used.add(c);
    }
    return stack.join('');
};
